12	// NativeRunnerConfigPresent reports whether the remote instance directory contains
13	// a fully-configured runner: the directory exists, run.sh/run.cmd is present, and .runner exists.
14	// This prevents EnsureSetup from skipping setup when only the .runner file exists but
15	// the runner binaries (run.sh) or directory are missing.
16	func NativeRunnerConfigPresent(h *host.Host, instanceName string) (bool, error) {
17		dir := h.RunnerDir(instanceName)
18		if h.OS == "windows" {
19			out, err := h.RunShell(fmt.Sprintf(
20				"%s; if ((Test-Path $runnerDir -PathType Container) -and (Test-Path (Join-Path $runnerDir 'run.cmd')) -and (Test-Path (Join-Path $runnerDir '.runner'))) { Write-Output 'yes' } else { Write-Output 'no' }",
21				windowsRunnerDirAssignment(h, "runnerDir", instanceName),
22			))
23			if err != nil {
24				return false, err
25			}
26			return strings.TrimSpace(out) == "yes", nil
27		}
28		out, err := h.Run(fmt.Sprintf("test -d %s && test -f %s/run.sh && test -f %s/.runner && echo yes || echo no", dir, dir, dir))
29		if err != nil {
30			return false, err
31		}
32		return strings.TrimSpace(out) == "yes", nil
33	}
