169	func (m *Manager) setupNative(h *host.Host, rc config.RunnerConfig) error {
170		version, err := m.GitHub.GetLatestRunnerVersion()
171		if err != nil {
172			return err
173		}
174	
175		ghArch := archForGitHub(h.Arch)
176		url := runnerTarballURL(version, h.OS, ghArch)
177		if url == "" {
178			return fmt.Errorf("unsupported OS/arch: %s/%s", h.OS, h.Arch)
179		}
180	
181		for _, name := range rc.InstanceNames() {
182			dir := h.RunnerDir(name)
183	
184			installed, _ := NativeRunnerConfigPresent(h, name)
185			if installed {
186				fmt.Fprintf(m.out(), "  %s: already installed, skipping\n", name)
187				continue
188			}
189	
190			fmt.Fprintf(m.out(), "  %s: installing runner v%s...\n", name, version)
191	
192			if h.OS == "linux" {
193				installDepsCmd := linuxElevatePrelude + `
194					if ! command -v curl >/dev/null 2>&1 || ! command -v tar >/dev/null 2>&1; then
195						if command -v apt-get >/dev/null 2>&1; then $SUDO apt-get update && $SUDO apt-get install -y curl tar;
196						elif command -v yum >/dev/null 2>&1; then $SUDO yum install -y curl tar;
197						elif command -v apk >/dev/null 2>&1; then $SUDO apk add curl tar;
198						fi
199					fi
200				`
201				if _, err := h.Run(installDepsCmd); err != nil {
202					fmt.Fprintf(m.out(), "  %s: warning: failed to ensure curl/tar are installed: %v\n", name, err)
203				}
204			}
205	
206			if h.OS == "windows" {
207				fmt.Fprintf(m.out(), "  %s: downloading runner package...\n", name)
208				if _, err := h.RunShell(windowsNativeInstallScript(h, name, version, url)); err != nil {
209					return fmt.Errorf("installing runner on Windows: %w", err)
210				}
211			} else {
212				tarball := fmt.Sprintf("%s/ghsr-runner-%s-%s.tar.gz", h.TempDir(), name, version)
213				fmt.Fprintf(m.out(), "  %s: downloading runner v%s...\n", name, version)
214				if _, err := h.Run(fmt.Sprintf("mkdir -p %s", dir)); err != nil {
215					return fmt.Errorf("creating runner directory: %w", err)
216				}
217				cmds := fmt.Sprintf(
218					"cd %s && tarball=%s && rm -f \"$tarball\" && "+
219						"curl -fSL --retry 3 --retry-delay 2 -o \"$tarball\" '%s'",
220					dir, tarball, url,
221				)
222				if _, err := h.Run(cmds); err != nil {
223					return fmt.Errorf("downloading runner: %w", err)
224				}
225				fmt.Fprintf(m.out(), "  %s: extracting runner...\n", name)
226				cmds = fmt.Sprintf("cd %s && tarball=%s && tar xzf \"$tarball\" && rm -f \"$tarball\"", dir, tarball)
227				if _, err := h.Run(cmds); err != nil {
228					return fmt.Errorf("extracting runner: %w", err)
229				}
230			}
231	
232			if h.OS == "linux" {
233				fmt.Fprintf(m.out(), "  %s: installing runner dependencies...\n", name)
234				depsCmd := fmt.Sprintf(
235					"cd %s && %s && $SUDO ./bin/installdependencies.sh",
236					dir, strings.TrimSpace(linuxElevatePrelude),
237				)
238				if _, err := h.Run(depsCmd); err != nil {
239					fmt.Fprintf(m.out(), "  %s: warning: failed to install runner dependencies: %v\n", name, err)
240				}
241			}
242	
243			regToken, err := m.GitHub.GetRegistrationTokenScoped(rc.Scope(), rc.ScopeTarget())
244			if err != nil {
245				return err
246			}
247	
248			labels := strings.Join(rc.EffectiveLabels(h.OS, h.Arch), ",")
249	
250			fmt.Fprintf(m.out(), "  %s: registering runner with GitHub...\n", name)
251			if h.OS == "windows" {
252				if _, err := h.RunShell(windowsNativeConfigScript(h, rc, name, regToken)); err != nil {
253					return fmt.Errorf("configuring runner on Windows: %w", err)
254				}
255			} else {
256				configURL := nativeConfigURL(rc)
257				configCmd := fmt.Sprintf(
258					"cd %s && ./config.sh --unattended --url '%s' --token '%s' --name '%s' --labels '%s' --work '_work' --replace",
259					dir, configURL, regToken, name, labels,
260				)
261				if rc.Group != "" {
262					configCmd += fmt.Sprintf(" --runnergroup '%s'", rc.Group)
263				}
264				if rc.Ephemeral {
265					configCmd += " --ephemeral"
266				}
267				if _, err := h.Run(configCmd); err != nil {
268					return fmt.Errorf("configuring runner: %w", err)
269				}
270			}
271	
272			fmt.Fprintf(m.out(), "  %s: configured\n", name)
273		}
274	
275		// For agentic runners, install gh-aw CLI on the host.
276		// gh-aw (GitHub Agentic Workflows) uses Docker on the host for AWF sandbox containers.
277		if rc.IsAgentic() && h.OS == "linux" {
278			fmt.Fprintf(m.out(), "  %s: installing gh-aw CLI for agentic profile...\n", rc.Name)
279			installGHAWCmd := `if [ -d ~/.local/share/gh/extensions/gh-aw ]; then
280				echo "gh-aw already installed"
281			else
282				curl -sL https://raw.githubusercontent.com/github/gh-aw/main/install-gh-aw.sh | bash
283			fi`
284			out, err := h.Run(installGHAWCmd)
285			if err != nil {
286				fmt.Fprintf(m.out(), "  %s: warning: failed to install gh-aw CLI: %v\n", rc.Name, err)
287			} else {
288				fmt.Fprintf(m.out(), "  %s: gh-aw CLI installed\n", rc.Name)
289				if out != "" {
290					fmt.Fprintf(m.out(), "  %s: gh-aw: %s\n", rc.Name, strings.TrimSpace(out))
291				}
292			}
293		}
294	
295		return nil
296	}
297	
298	func (m *Manager) startNative(h *host.Host, rc config.RunnerConfig, instanceName string) error {
299		return m.startNativeOnce(h, rc, instanceName, true)
300	}
301	
302	// startNativeOnce starts the runner and optionally detects a stale registration.
303	// When retryOnStale is true and the runner exits immediately with the stale-registration
304	// message, it clears local credentials, re-runs setupNative, and retries once.
305	func (m *Manager) startNativeOnce(h *host.Host, rc config.RunnerConfig, instanceName string, retryOnStale bool) error {
306		dir := h.RunnerDir(instanceName)
307	
308		ok, err := NativeRunnerConfigPresent(h, instanceName)
309		if err != nil {
310			return fmt.Errorf("checking runner install at %s: %w", dir, err)
311		}
312		if !ok {
313			fmt.Fprintf(m.out(), "  %s: not installed, running setup (this takes a few minutes)...\n", instanceName)
314			if setupErr := m.setupNative(h, rc); setupErr != nil {
315				return fmt.Errorf("auto-setup for %s: %w", instanceName, setupErr)
316			}
317		}
318	
319		if h.OS == "windows" {
320			out, err := h.RunShell(windowsNativeStartScript(h, instanceName))
321			if err != nil {
322				return err
323			}
324			fmt.Fprintf(m.out(), "  %s: %s\n", instanceName, strings.TrimSpace(out))
325	
326			if retryOnStale {
327				fmt.Fprintf(m.out(), "  %s: waiting for runner to initialize...\n", instanceName)
328				checkOut, _ := h.RunShell(windowsCheckStaleRegistration(h, instanceName))
329				if strings.TrimSpace(checkOut) == "stale" {
330					return m.handleStaleRegistration(h, rc, instanceName)
331				}
332			}
333			return nil
334		}
335	
336		// Unix (Linux / macOS)
337		cmd := fmt.Sprintf(
338			`cd %s; pid_file=".runner_pid"; `+
339				`if [ -f "$pid_file" ] && kill -0 "$(cat "$pid_file")" 2>/dev/null; then echo "already running"; exit 0; fi; `+
340				`nohup ./run.sh > runner.log 2>&1 & { echo $!; } > "$pid_file"; echo "started PID $!"`,
341			dir,
342		)
343		out, err := h.Run(cmd)
344		if err != nil {
345			return err
346		}
347		fmt.Fprintf(m.out(), "  %s: %s\n", instanceName, strings.TrimSpace(out))
348	
349		if retryOnStale {
350			fmt.Fprintf(m.out(), "  %s: waiting for runner to initialize...\n", instanceName)
351			checkCmd := fmt.Sprintf(
352				`sleep 5 && cd %s && pid=$(cat .runner_pid 2>/dev/null) && `+
353					`if [ -n "$pid" ] && kill -0 "$pid" 2>/dev/null; then echo ok; `+
354					`elif grep -q %q runner.log 2>/dev/null; then echo stale; `+
355					`else echo ok; fi`,
356				dir, staleRegistrationMsg,
357			)
358			checkOut, _ := h.Run(checkCmd)
359			if strings.TrimSpace(checkOut) == "stale" {
360				return m.handleStaleRegistration(h, rc, instanceName)
361			}
362		}
363		return nil
364	}
365	
366	func (m *Manager) handleStaleRegistration(h *host.Host, rc config.RunnerConfig, instanceName string) error {
367		fmt.Fprintf(m.out(), "  %s: registration expired on GitHub, re-configuring...\n", instanceName)
368		dir := h.RunnerDir(instanceName)
369	
370		if h.OS == "windows" {
371			h.RunShell(windowsDeleteRunnerConfig(h, instanceName))
372		} else {
373			h.Run(fmt.Sprintf("rm -f %s/.runner %s/.credentials %s/.credentials_rsaparams", dir, dir, dir))
374		}
375	
376		if err := m.setupNative(h, rc); err != nil {
377			return fmt.Errorf("re-configuring after stale registration: %w", err)
378		}
379	
380		return m.startNativeOnce(h, rc, instanceName, false)
381	}
382	
383	func (m *Manager) stopNative(h *host.Host, instanceName string) error {
384		dir := h.RunnerDir(instanceName)
385	
386		if h.OS == "windows" {
387			cmd := fmt.Sprintf(
388				"%s; $pidFile = Join-Path $runnerDir '.runner_pid'; "+
389					"if (-not (Test-Path $pidFile)) { Write-Host 'not running'; exit 0 }; "+
390					"$p = (Get-Content $pidFile | Select-Object -First 1).Trim(); "+
391					"$null = & taskkill.exe /PID $p /T /F 2>&1; "+
392					"if ($LASTEXITCODE -eq 0) { Write-Host 'stopped' } else { Write-Host 'not running' }; "+
393					"Remove-Item $pidFile -Force -EA SilentlyContinue",
394				windowsRunnerDirAssignment(h, "runnerDir", instanceName),
395			)
396			out, err := h.RunShell(cmd)
397			if err != nil {
398				return err
399			}
400			fmt.Fprintf(m.out(), "  %s: %s\n", instanceName, strings.TrimSpace(out))
401			return nil
402		}
403	
404		cmd := fmt.Sprintf(
405			`cd %s && pid_file=".runner_pid" && `+
406				`if [ ! -f "$pid_file" ]; then echo "not running"; exit 0; fi && `+
407				`pid=$(cat "$pid_file") && `+
408				`if ! kill -0 "$pid" 2>/dev/null; then echo "not running"; rm -f "$pid_file"; exit 0; fi && `+
409				`kill "$pid" && `+
410				`for i in $(seq 1 10); do kill -0 "$pid" 2>/dev/null || break; sleep 1; done && `+
411				`kill -0 "$pid" 2>/dev/null && kill -9 "$pid" 2>/dev/null; `+
412				`rm -f "$pid_file" && echo "stopped"`,
413			dir,
414		)
415		out, err := h.Run(cmd)
416		if err != nil {
417			return err
418		}
419		fmt.Fprintf(m.out(), "  %s: %s\n", instanceName, strings.TrimSpace(out))
420		return nil
421	}
422	
423	func (m *Manager) removeNative(h *host.Host, rc config.RunnerConfig, instanceName string) error {
424		dir := h.RunnerDir(instanceName)
425	
426		_ = m.stopNative(h, instanceName)
427	
428		removeToken, err := m.GitHub.GetRemovalTokenScoped(rc.Scope(), rc.ScopeTarget())
429		if err != nil {
430			fmt.Fprintf(m.out(), "  %s: warning: could not get removal token: %v\n", instanceName, err)
431		} else {
432			if h.OS == "windows" {
433				cmd := fmt.Sprintf(
434					"%s; Set-Location -Path $runnerDir; & .\\config.cmd remove --token %s",
435					windowsRunnerDirAssignment(h, "runnerDir", instanceName),
436					powerShellSingleQuoted(removeToken),
437				)
438				h.RunShell(cmd)
439			} else {
440				cmd := fmt.Sprintf("cd %s && ./config.sh remove --token '%s'", dir, removeToken)
441				h.Run(cmd)
442			}
443			fmt.Fprintf(m.out(), "  %s: deregistered\n", instanceName)
444		}
445	
446		if h.OS == "windows" {
447			h.RunShell(fmt.Sprintf("%s; Remove-Item -Recurse -Force $runnerDir", windowsRunnerDirAssignment(h, "runnerDir", instanceName)))
448		} else {
449			h.Run(fmt.Sprintf("rm -rf %s", dir))
450		}
451	
452		fmt.Fprintf(m.out(), "  %s: removed\n", instanceName)
453		return nil
454	}
455	
456	func (m *Manager) statusNative(h *host.Host, instanceName string) string {
457		dir := h.RunnerDir(instanceName)
458	
459		if kind, err := autostart.Detect(h, instanceName); err == nil && kind != autostart.KindNone {
460			active, err := autostart.IsServiceActive(h, instanceName, kind)
461			if err != nil {
462				return "unknown"
463			}
464			if active {
465				return "running"
466			}
467			return "stopped"
468		}
469	
470		if h.OS == "windows" {
471			cmd := fmt.Sprintf(
472				"%s; if (-not (Test-Path (Join-Path $runnerDir '.runner'))) { Write-Host 'not installed'; exit 0 }; "+
473					"$pidFile = Join-Path $runnerDir '.runner_pid'; "+
474					"if (-not (Test-Path $pidFile)) { Write-Host 'stopped'; exit 0 }; "+
475					"$p = Get-Content $pidFile; "+
476					"try { Get-Process -Id $p -EA Stop | Out-Null; Write-Host 'running' } catch { Write-Host 'stopped' }",
477				windowsRunnerDirAssignment(h, "runnerDir", instanceName),
478			)
479			out, _ := h.RunShell(cmd)
480			return strings.TrimSpace(out)
481		}
482	
483		cmd := fmt.Sprintf(
484			`d="%s" && `+
485				`if [ ! -f "$d/.runner" ]; then echo "not installed"; exit 0; fi && `+
486				`pid_file="$d/.runner_pid" && `+
487				`if [ ! -f "$pid_file" ]; then echo "stopped"; exit 0; fi && `+
488				`pid=$(cat "$pid_file") && `+
489				`if kill -0 "$pid" 2>/dev/null; then echo "running"; else echo "stopped"; fi`,
490			dir,
491		)
492		out, err := h.Run(cmd)
493		if err != nil {
494			return "unknown"
495		}
496		return strings.TrimSpace(out)
497	}
498	
499	func (m *Manager) logsNative(h *host.Host, instanceName string) (string, error) {
500		dir := h.RunnerDir(instanceName)
501	
502		if h.OS == "windows" {
503			cmd := fmt.Sprintf(
504				"%s; $logFile = Join-Path $runnerDir 'runner.log'; "+
505					"$diagDir = Join-Path $runnerDir '_diag'; "+
506					"$tailMain = { if (Test-Path $logFile) { $lines = @(Get-Content -LiteralPath $logFile -Tail 50 -EA SilentlyContinue); "+
507					"$j = [string]::Join([Environment]::NewLine, $lines); "+
508					"if ($lines.Count -gt 0 -and ($j -match '\\S')) { $j } else { $null } } else { $null } }; "+
509					"$main = & $tailMain; "+
510					"if ($null -ne $main) { Write-Output $main } "+
511					"elseif (Test-Path $diagDir) { "+
512					"$latest = Get-ChildItem -Path $diagDir -Filter *.log -File -EA SilentlyContinue | Sort-Object LastWriteTime -Descending | Select-Object -First 1; "+
513					"if ($latest) { Write-Output ('--- _diag/' + $latest.Name + ' (last 50 lines) ---'); Get-Content -LiteralPath $latest.FullName -Tail 50 } "+
514					"else { Write-Output 'no logs found' } } "+
515					"else { Write-Output 'no logs found' }",
516				windowsRunnerDirAssignment(h, "runnerDir", instanceName),
517			)
518			return h.RunShell(cmd)
519		}
520	
521		cmd := fmt.Sprintf("tail -50 %s/runner.log 2>/dev/null || echo 'no logs found'", dir)
522		return h.Run(cmd)
