1	package config
2	
3	import (
4		"fmt"
5		"os"
6		"runtime"
7		"strings"
8	
9		"gopkg.in/yaml.v3"
10	)
11	
12	const LocalAddr = "local"
13	
14	func IsLocalAddr(addr string) bool {
15		return strings.EqualFold(strings.TrimSpace(addr), LocalAddr)
16	}
17	
18	type Config struct {
19		GitHub  GitHubConfig          `yaml:"github"`
20		Hosts   map[string]HostConfig `yaml:"hosts"`
21		Runners []RunnerConfig        `yaml:"runners"`
22	}
23	
24	type GitHubConfig struct {
25		PAT string `yaml:"pat"`
26	}
27	
28	type HostConfig struct {
29		Addr      string `yaml:"addr"`
30		OS        string `yaml:"os"`
31		Arch      string `yaml:"arch"`
32		WindowsPS string `yaml:"windows_ps"` // powershell (default) or pwsh — which exe runs encoded remote scripts on Windows
33	}
34	
35	type RunnerConfig struct {
36		Name      string   `yaml:"name"`
37		Repo      string   `yaml:"repo"`
38		Org       string   `yaml:"org"`
39		Group     string   `yaml:"group"`
40		Host      string   `yaml:"host"`
41		Count     int      `yaml:"count"`
42		Labels    []string `yaml:"labels"`
43		Ephemeral bool     `yaml:"ephemeral"`
44		Profile   string   `yaml:"profile"` // "agentic" for GitHub Agentic Workflows
45	}
46	
47	// IsAgentic returns true if the runner uses the agentic profile.
48	func (rc *RunnerConfig) IsAgentic() bool {
49		return rc.Profile == "agentic"
50	}
51	
52	// Scope returns "repo" or "org" depending on how the runner is registered.
53	func (rc *RunnerConfig) Scope() string {
54		if rc.Org != "" {
55			return "org"
56		}
57		return "repo"
58	}
59	
60	// ScopeTarget returns the repo (owner/repo) or org name used for GitHub API calls.
61	func (rc *RunnerConfig) ScopeTarget() string {
62		if rc.Org != "" {
63			return rc.Org
64		}
65		return rc.Repo
66	}
67	
68	// EffectiveMode always returns "native" (docker mode has been removed).
69	func (rc *RunnerConfig) EffectiveMode(_ string) string {
70		return "native"
71	}
72	
73	// DefaultLabels generates standard GitHub Actions labels based on host OS and arch.
74	func DefaultLabels(hostOS, arch string) []string {
75		labels := []string{"self-hosted"}
76	
77		osLabel := ""
78		switch hostOS {
79		case "linux":
80			osLabel = "Linux"
81		case "darwin":
82			osLabel = "macOS"
83		case "windows":
84			osLabel = "Windows"
85		}
86		if osLabel != "" {
87			labels = append(labels, osLabel)
88		}
89	
90		archLabel := ""
91		switch arch {
92		case "amd64":
93			archLabel = "X64"
94		case "arm64":
95			archLabel = "ARM64"
96		}
97		if archLabel != "" {
98			labels = append(labels, archLabel)
99		}
100	
101		return labels
102	}
103	
104	// EffectiveLabels returns the runner's labels, auto-generating them from host info if empty.
105	// For agentic profile runners, "agentic" label is always appended.
106	func (rc *RunnerConfig) EffectiveLabels(hostOS, arch string) []string {
107		var labels []string
108		if len(rc.Labels) > 0 {
109			labels = rc.Labels
110		} else {
111			labels = DefaultLabels(hostOS, arch)
112		}
113		if rc.IsAgentic() && !hasLabel(labels, "agentic") {
114			labels = append(labels, "agentic")
115		}
116		return labels
117	}
118	
119	func hasLabel(labels []string, target string) bool {
120		for _, l := range labels {
121			if strings.EqualFold(l, target) {
122				return true
123			}
124		}
125		return false
126	}
127	
128	func (rc *RunnerConfig) InstanceNames() []string {
129		count := rc.Count
130		if count < 1 {
131			count = 1
132		}
133		names := make([]string, count)
134		for i := range count {
135			names[i] = fmt.Sprintf("%s-%d", rc.Name, i+1)
136		}
137		return names
138	}
139	
140	func Load(path string) (*Config, error) {
141		data, err := os.ReadFile(path)
142		if err != nil {
143			return nil, fmt.Errorf("reading config: %w", err)
144		}
145	
146		var cfg Config
147		if err := yaml.Unmarshal(data, &cfg); err != nil {
148			return nil, fmt.Errorf("parsing config: %w", err)
149		}
150	
151		cfg.resolveEnvRefs()
152		cfg.applyDefaults()
153	
154		if err := cfg.Validate(); err != nil {
155			return nil, err
156		}
157	
158		return &cfg, nil
159	}
160	
161	func (c *Config) resolveEnvRefs() {
162		c.GitHub.PAT = resolveEnv(c.GitHub.PAT)
163	}
164	
165	func resolveEnv(val string) string {
166		if strings.HasPrefix(val, "env:") {
167			envVar := strings.TrimPrefix(val, "env:")
168			return os.Getenv(envVar)
169		}
170		return val
171	}
172	
173	func normalizeArch(goarch string) string {
174		switch goarch {
175		case "amd64", "arm64":
176			return goarch
177		default:
178			return goarch
179		}
180	}
181	
182	func (c *Config) applyDefaults() {
183		for name, h := range c.Hosts {
184			if IsLocalAddr(h.Addr) {
185				if h.OS == "" {
186					h.OS = runtime.GOOS
187				}
188				if h.Arch == "" {
189					h.Arch = normalizeArch(runtime.GOARCH)
190				}
191				c.Hosts[name] = h
192			}
193		}
194		for i := range c.Runners {
195			if c.Runners[i].Count < 1 {
196				c.Runners[i].Count = 1
197			}
198			c.Runners[i].applyAgenticDefaults()
199		}
200	}
201	
202	func (rc *RunnerConfig) applyAgenticDefaults() {
203		if !rc.IsAgentic() {
204			return
205		}
206		// Agentic runners get "agentic" label auto-added if not present.
207		if !hasLabel(rc.Labels, "agentic") {
208			rc.Labels = append(rc.Labels, "agentic")
209		}
210	}
211	
212	func (c *Config) Validate() error {
213		if c.GitHub.PAT != "" {
214			return fmt.Errorf("github.pat is no longer supported; remove it from runners.yml and authenticate with `gh auth login`")
215		}
216	
217		if len(c.Hosts) == 0 {
218			return fmt.Errorf("at least one host must be defined")
219		}
220	
221		for name, h := range c.Hosts {
222			if h.Addr == "" {
223				return fmt.Errorf("host %q: addr is required (use \"local\" for the current machine)", name)
224			}
225			// os and arch may be empty for remote hosts -- they are auto-detected over SSH before operations.
226			if h.OS != "" {
227				switch h.OS {
228				case "linux", "darwin", "windows":
229				default:
230					return fmt.Errorf("host %q: os must be linux, darwin, or windows (got %q)", name, h.OS)
231				}
232			}
233			if h.Arch != "" {
234				switch h.Arch {
235				case "amd64", "arm64":
236				default:
237					return fmt.Errorf("host %q: arch must be amd64 or arm64 (got %q)", name, h.Arch)
238				}
239			}
240			if h.WindowsPS != "" {
241				if h.OS != "" && h.OS != "windows" {
242					return fmt.Errorf("host %q: windows_ps is only valid when os is windows", name)
243				}
244				switch strings.ToLower(strings.TrimSpace(h.WindowsPS)) {
245				case "powershell", "pwsh":
246				default:
247					return fmt.Errorf("host %q: windows_ps must be powershell or pwsh (got %q)", name, h.WindowsPS)
248				}
249			}
250		}
251	
252		if len(c.Runners) == 0 {
253			return fmt.Errorf("at least one runner must be defined")
254		}
255	
256		for _, r := range c.Runners {
257			if r.Name == "" {
258				return fmt.Errorf("runner name is required")
259			}
260			if r.Repo == "" && r.Org == "" {
261				return fmt.Errorf("runner %q: repo or org is required", r.Name)
262			}
263			if r.Repo != "" && r.Org != "" {
264				return fmt.Errorf("runner %q: specify repo or org, not both", r.Name)
265			}
266			if r.Group != "" && r.Org == "" {
